from typing import Any, Dict, List, Optional, Tuple, Union, Iterable


def process_records(records: List[Dict[str, Any]], schema: Dict[str, type], required_fields: List[str], group_by_field: Optional[str] = None) -> Dict[str, Any]:
    errors: List[str] = []
    processed: List[Dict[str, Any]] = []
    aggregates: Dict[str, Any] = {}
    field_counts: Dict[str, int] = {}
    groups: Dict[Any, List[Dict[str, Any]]] = {}
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            errors.append(f\"Record {rec} is not a dict\")
            return False
        for field in required_fields:
            if field not in rec:
                errors.append(f\"Missing required field {field} in record {rec}\")
                return False
        return True
    def _transform_record(rec: Dict[str, Any]) -> Dict[str, Any]:
        transformed = {}
        for field, typ in schema.items():
            if field in rec:
                val = rec[field]
                if not isinstance(val, typ):
                    try:
                        val = typ(val)
                    except Exception:
                        errors.append(f\"Field {field} in record {rec} cannot be cast to {typ.__name__}\")
                        continue
                transformed[field] = val
        return transformed
    def _aggregate_record(rec: Dict[str, Any]) -> None:
        for field, val in rec.items():
            if isinstance(val, (int, float)):
                aggregates.setdefault(field, 0)
                aggregates[field] += val
            field_counts[field] = field_counts.get(field, 0) + 1
    def _group_record(rec: Dict[str, Any]) -> None:
        if group_by_field and group_by_field in rec:
            key = rec[group_by_field]
            groups.setdefault(key, []).append(rec)
        else:
            groups.setdefault(None, []).append(rec)
    for rec in records:
        if not _validate_record(rec):
            continue
        transformed = _transform_record(rec)
        if not transformed:
            continue
        processed.append(transformed)
        _aggregate_record(transformed)
        _group_record(transformed)
    def _compute_percentiles(values: List[Union[int, float]]) -> Dict[str, float]:
        if not values:
            return {}
        sorted_vals = sorted(values)
        n = len(sorted_vals)
        def _p(idx: int) -> float:
            return sorted_vals[int(idx * n)]
        return {
            \"25th\": _p(0.25),
            \"50th\": _p(0.5),
            \"75th\": _p(0.75),
        }
    percentiles: Dict[str, Dict[str, float]] = {}
    for field, val in aggregates.items():
        if isinstance(val, (int, float)):
            # gather all values for this field
            vals: List[Union[int, float]] = [rec[field] for rec in processed if field in rec]
            percentiles[field] = _compute_percentiles(vals)
    summary = {
        \"total_records\": len(records),
        \"processed_records\": len(processed),
        \"errors\": errors,
        \"field_counts\": field_counts,
        \"aggregates\": aggregates,
        \"percentiles\": percentiles,
        \"groups\": {k: len(v) for k, v in groups.items()},
    }
    return summary

