def process_user_data(
    raw_records: Iterable[Dict[str, Any]],
    required_fields: List[str],
    email_pattern: str = r"^[^@]+@[^@]+\\.[^@]+$",
    max_age: int = 120,
) -> Dict[str, Any]:
    email_regex = re.compile(email_pattern)
    processed: List[Dict[str, Any]] = []
    errors: List[Tuple[int, str]] = []
    stats: Dict[str, Any] = {"total": 0, "valid": 0, "invalid": 0}

    def _validate(record: Dict[str, Any], idx: int) -> bool:
        missing = [f for f in required_fields if f not in record]
        if missing:
            errors.append((idx, f"Missing fields: {missing}"))
            return False
        if "email" in record and not email_regex.match(record["email"]):
            errors.append((idx, f"Invalid email: {record['email']}") )
            return False
        if "age" in record:
            try:
                age = int(record["age"])
                if age < 0 or age > max_age:
                    errors.append((idx, f"Age out of bounds: {age}"))
                    return False
            except (ValueError, TypeError):
                errors.append((idx, f"Non-integer age: {record['age']}") )
                return False
        return True

    def _normalize(record: Dict[str, Any]) -> Dict[str, Any]:
        norm = {}
        for key, value in record.items():
            if isinstance(value, str):
                norm[key] = value.strip()
            else:
                norm[key] = value
        return norm

    for idx, rec in enumerate(raw_records):
        stats["total"] += 1
        if not isinstance(rec, dict):
            errors.append((idx, "Record is not a dict"))
            continue
        if _validate(rec, idx):
            norm_rec = _normalize(rec)
            processed.append(norm_rec)
            stats["valid"] += 1
        else:
            stats["invalid"] += 1

    summary = {
        "stats": stats,
        "errors": errors,
        "processed_count": len(processed),
    }

    def _write_json(path: str, data: Any) -> None:
        with open(path, "w", encoding="utf-8") as f:
            json.dump(data, f, ensure_ascii=False, indent=2)

    if processed:
        _write_json("cleaned_users.json", processed)

    return summary

