from typing import Any, Dict, Iterable, List, Callable, Optional, Tuple

def process_dataset(
    rows: Iterable[Dict[str, Any]],
    required_fields: List[str],
    transform_map: Dict[str, Callable[[Any], Any]],
) -> Dict[str, Any]:
    # Validate each row has required fields
    def _validate(row: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in row:
                return False
        return True

    # Apply transformations to a row
    def _transform(row: Dict[str, Any]) -> Dict[str, Any]:
        new_row = {}
        for key, value in row.items():
            if key in transform_map:
                try:
                    new_row[key] = transform_map[key](value)
                except Exception:
                    new_row[key] = None
            else:
                new_row[key] = value
        return new_row

    # Aggregate statistics
    def _aggregate(rows_iter: Iterable[Dict[str, Any]]) -> Tuple[Dict[str, int], Dict[str, float]]:
        counts: Dict[str, int] = {}
        sums: Dict[str, float] = {}
        for r in rows_iter:
            for k, v in r.items():
                if isinstance(v, (int, float)):
                    counts[k] = counts.get(k, 0) + 1
                    sums[k] = sums.get(k, 0.0) + float(v)
        averages: Dict[str, float] = {}
        for k, total in sums.items():
            averages[k] = total / counts[k] if counts[k] else 0.0
        return counts, averages

    valid_rows: List[Dict[str, Any]] = []
    errors: List[str] = []
    for idx, row in enumerate(rows):
        if not isinstance(row, dict):
            errors.append(f"Row {idx} is not a dict")
            continue
        if not _validate(row):
            errors.append(f"Row {idx} missing required fields")
            continue
        try:
            transformed = _transform(row)
            valid_rows.append(transformed)
        except Exception as e:
            errors.append(f"Row {idx} transformation error: {e}")

    counts, averages = _aggregate(valid_rows)

    result: Dict[str, Any] = {
        "valid_count": len(valid_rows),
        "error_count": len(errors),
        "errors": errors,
        "counts": counts,
        "averages": averages,
        "sample": valid_rows[:5] if valid_rows else [],
    }

    return result

from typing import Any, Dict, Iterable, List, Optional, Tuple


def analyze_text_corpus(
    documents: Iterable[Tuple[str, str]],
    stopwords: Optional[Iterable[str]] = None,
    min_word_length: int = 3,
    max_word_length: int = 20,
) -> Dict[str, Any]:
    stop_set = {w.lower() for w in (stopwords or [])}
    word_counts: Dict[str, int] = {}
    doc_word_lists: Dict[str, List[str]] = {}
    total_words = 0
    total_docs = 0

    def _clean_word(word: str) -> Optional[str]:
        w = word.strip().lower()
        if not w:
            return None
        if w in stop_set:
            return None
        if not (min_word_length <= len(w) <= max_word_length):
            return None
        return w

    def _process_document(doc_id: str, text: str) -> List[str]:
        words = []
        for raw in text.split():
            cleaned = _clean_word(raw)
            if cleaned is None:
                continue
            words.append(cleaned)
            word_counts[cleaned] = word_counts.get(cleaned, 0) + 1
        return words

    for doc_id, text in documents:
        if not isinstance(doc_id, str):
            doc_id = str(doc_id)
        if not isinstance(text, str):
            continue
        cleaned_words = _process_document(doc_id, text)
        doc_word_lists[doc_id] = cleaned_words
        total_words += len(cleaned_words)
        total_docs += 1

    if total_docs == 0:
        return {
            "error": "No valid documents processed",
            "stats": {},
        }

    top_words = sorted(word_counts.items(), key=lambda kv: (-kv[1], kv[0]))[:10]
    avg_words_per_doc = total_words / total_docs

    def _word_frequency(word: str) -> int:
        return word_counts.get(word.lower(), 0)

    def _most_common_in_doc(doc_id: str) -> Optional[Tuple[str, int]]:
        words = doc_word_lists.get(doc_id)
        if not words:
            return None
        freq: Dict[str, int] = {}
        for w in words:
            freq[w] = freq.get(w, 0) + 1
        return max(freq.items(), key=lambda kv: kv[1])

    most_common_per_doc: Dict[str, Tuple[str, int]] = {}
    for d in doc_word_lists:
        mc = _most_common_in_doc(d)
        if mc:
            most_common_per_doc[d] = mc

    return {
        "total_documents": total_docs,
        "total_words": total_words,
        "average_words_per_document": avg_words_per_doc,
        "top_words": [{"word": w, "count": c} for w, c in top_words],
        "most_common_word_per_document": most_common_per_doc,
        "word_frequency": _word_frequency,
    }

