def compute_weighted_moving_average(
    data: List[float],
    window_size: int,
    weights: Optional[List[float]] = None,
    normalize: bool = True,
    min_valid: Optional[float] = None,
    max_valid: Optional[float] = None,
) -> List[Tuple[int, float]]:
    # Validate input parameters
    def _validate_params() -> None:
        if window_size <= 0:
            raise ValueError("window_size must be positive")
        if not data:
            raise ValueError("data list cannot be empty")
        if weights is not None:
            if len(weights) != window_size:
                raise ValueError("weights length must match window_size")
            if any(w < 0 for w in weights):
                raise ValueError("weights must be non-negative")
        if min_valid is not None and max_valid is not None:
            if min_valid > max_valid:
                raise ValueError("min_valid cannot exceed max_valid")

    # Clamp values to optional bounds
    def _apply_bounds(val: float) -> float:
        if min_valid is not None and val < min_valid:
            return min_valid
        if max_valid is not None and val > max_valid:
            return max_valid
        return val

    # Handle missing values by propagating last known value or zero
    def _handle_missing(window: List[float]) -> List[float]:
        last_known: Optional[float] = None
        result: List[float] = []
        for v in window:
            if v is None:
                if last_known is not None:
                    result.append(last_known)
                else:
                    result.append(0.0)
            else:
                result.append(v)
                last_known = v
        return result

    # Compute weighted average for a single window
    def _compute_window(start: int) -> float:
        raw_window = data[start:start + window_size]
        window = _handle_missing(raw_window)
        window = [_apply_bounds(v) for v in window]
        if weights is None:
            return sum(window) / window_size
        weighted_sum = sum(v * w for v, w in zip(window, weights))
        denom = sum(weights)
        return weighted_sum / denom if denom != 0 else 0.0

    # Optional normalization of the window result
    def _normalize_window(avg: float, start: int) -> float:
        if not normalize:
            return avg
        sub_window = data[start:start + window_size]
        sub_window = [_apply_bounds(v) for v in sub_window]
        max_val = max(sub_window)
        min_val = min(sub_window)
        if max_val == min_val:
            return 0.0
        return (avg - min_val) / (max_val - min_val)

    _validate_params()

    result: List[Tuple[int, float]] = []

    for i in range(len(data) - window_size + 1):
        avg = _compute_window(i)
        norm_avg = _normalize_window(avg, i)
        result.append((i, norm_avg))

    return result

