from typing import Iterable, Iterator, Tuple, Callable
import time
import contextlib

def log_decorator(func: Callable) -> Callable:
    def wrapper(*args, **kwargs):
        print(f"[{time.strftime('%H:%M:%S')}] Entering {func.__name__}")
        result = func(*args, **kwargs)
        print(f"[{time.strftime('%H:%M:%S')}] Exiting {func.__name__}")
        return result
    return wrapper

@log_decorator
def number_pipeline(numbers: Iterable[int]) -> Iterator[Tuple[int, int, int]]:
    def _validate(n: int) -> int:
        if not isinstance(n, int):
            raise TypeError(f"Expected int, got {type(n).__name__}")
        return n

    def _filter_non_negative(n: int) -> bool:
        return n >= 0

    def _square(n: int) -> int:
        return n * n

    def _cumulative_sum(values: Iterable[int]) -> Iterator[int]:
        total = 0
        for v in values:
            total += v
            yield total

    @contextlib.contextmanager
    def _yield_timer() -> Iterator[Callable[[], None]]:
        start = time.perf_counter()
        def stop():
            elapsed = time.perf_counter() - start
            print(f"Yield took {elapsed:.6f}s")
        yield stop
        stop()

    with _yield_timer() as timer:
        squared_values: List[int] = []
        for raw in numbers:
            try:
                num = _validate(raw)
            except TypeError:
                continue
            if not _filter_non_negative(num):
                continue
            sq = _square(num)
            squared_values.append(sq)
            timer()
            yield (num, sq, sum(squared_values))

    print("Pipeline finished.")
